def load_scores(text):
    scores = []
    for line_number, line in enumerate(text.splitlines(), start=1):
        stripped = line.strip()
        if not stripped:
            continue
        name, value = stripped.split(',', 1)
        scores.append((name.strip(), int(value)))
    return scores

import pytest

from scores import load_scores


def test_load_scores_skips_blank_lines():
    assert load_scores('Ada,10\n\nGrace,8') == [
        ('Ada', 10),
        ('Grace', 8),
    ]


def test_load_scores_rejects_malformed_rows():
    with pytest.raises(ValueError):
        load_scores('Ada')

